SELECT DISTINCT ?modelName ?modelId ?taskName WHERE {
  ?task a bboExt:ChoreographyTask ;
        bbo:name ?taskName ;
        bboExt:initiatingParticipantRef ?ehqRef ;
        tai:belongsTo ?choreo .

  FILTER(CONTAINS(LCASE(STR(?taskName)), LCASE("data analysis")))

  ?choreo tai:belongsTo ?model .
  ?model a bboExt:Model ;
         bbo:name ?modelName .
  OPTIONAL { ?model tai:originalId ?modelId . }

  ?p a bboExt:Participant ;
     tai:belongsTo ?choreo ;
     bbo:name ?pName ;
     FILTER(CONTAINS(LCASE(STR(?pName)), "the client ehq")) .

  ?q a bboExt:Participant ;
     tai:belongsTo ?choreo ;
     bbo:name ?qName ;
     FILTER(CONTAINS(LCASE(STR(?qName)), "the client elc")) .

  FILTER( STRENDS(STR(?p), STR(?ehqRef)) )
}
LIMIT 25
